section.programlisting:
1 #ifndef HDEF_EXCEPTION
2 #define HDEF_EXCEPTION
3 
4 #include <stdexcept>
5 #include <string>
6 #include <format>
7 #include <source_location>
8 
9 namespace Mochi
10 {
11     class EngineError : public std::runtime_error
12     {
13     public:
14         explicit EngineError(const std::string &msg, std::source_location loc = std::source_location::current())
15             : std::runtime_error(std::format("{} [{}:{}]", msg, loc.file_name(), loc.line())) {};
16     };
17 
18     class ResourceNotFoundError : public EngineError
19     {
20     public:
21         explicit ResourceNotFoundError(const std::string &resource, const std::string &hint = "") : EngineError(std::format("Resource not found: {} (({}))", resource, hint)) {}
22     };
23 
24     class SystemInitializationError : public EngineError
25     {
26     public:
27         explicit SystemInitializationError(const std::string &system, const std::string &msg) : EngineError(std::format("Error initializing system {}: {}", system, msg)) {}
28     };
29 
30     class MalformedInputAction : public EngineError
31     {
32     public:
33         explicit MalformedInputAction(std::source_location loc = std::source_location::current()) : EngineError("JSON input action was malformed", loc) {}
34     };
35 
36     class AudioOperationError : public EngineError
37     {
38     public:
39         explicit AudioOperationError(const std::string &operation, const std::string &msg) : EngineError(std::format("Audio operation failed: {} (({}))", operation, msg)) {}
40     };
41 }
42 #endif
